schemas.ddl:
-- Erst die unabhängigen Tabellen
create table l (
  lnr    varchar(2)   not null primary key
, lname  varchar(6)   not null
, rabatt decimal(3)   not null default 15
, stadt  varchar(6)   not null default 'Wien'
);

create table t (
  tnr    varchar(2)   not null primary key
, tname  varchar(8)   not null
, farbe  varchar(5)   not null
, preis  decimal(4,2) not null
);

-- Dann die Zwischentabelle (m:n)
create table lt (
  lnr    varchar(2)  not null references l   -- FK auf Lieferant
, tnr    varchar(2)  not null references t   -- FK auf Teil
, menge  decimal(4)  not null check(menge > 0)  -- Beziehungsattribut
, primary key (lnr, tnr)   -- zusammengesetzter PK
);

create table kurs (
  knr      integer     not null primary key
, bezeichn varchar(20) not null
, tage     integer     not null
, preis    decimal(8,2)
);

create table referent (
  pnr     integer  not null primary key
, gebdat  date     not null
, seit    date     not null
, titel   varchar(20)
);

create table geeignet (
  knr  integer  not null references kurs      -- FK auf kurs
, pnr  integer  not null references referent  -- FK auf referent
, primary key (knr, pnr)   -- zusammengesetzter PK
);

create table Angestellter (
  SVN      varchar(10)  not null primary key
, Vorname  varchar(16)  not null
, Nachname varchar(16)  not null
);

-- Rekursive m:n: beide FKs zeigen auf Angestellter
create table untersteht (
  SVN       varchar(10)  not null references Angestellter  -- der Untergebene
, LeiterSVN varchar(10)  not null references Angestellter  -- der Vorgesetzte
, primary key (SVN, LeiterSVN)
);

create table person (
  SVN      float        not null primary key
, Vorname  varchar(32)  not null
, Nachname varchar(32)  not null
);

create table schule (
  SchulNr     integer      not null primary key
, Bezeichnung varchar(32)  not null
, Schultyp    varchar(20)  not null
);

create table besucht (
  SVN     float        not null references person
, SchulNr integer      not null references schule
, Monate  integer      not null
, Kosten  decimal(5,2)  not null check(Kosten >= 0 and Kosten <= 100000)
, primary key (SVN, SchulNr)
);

-- Starker Entitytyp zuerst
create table Kino (
  KinoNr  integer      not null primary key
, Name    varchar(32)  not null
);

-- Abhängiger Entitytyp: FK zuerst, Teil des PK
create table Saal (
  KinoNr  integer  not null references Kino   -- FK = Teil des PK
, SaalNr  integer  not null                   -- Teilschlüssel
, primary key (KinoNr, SaalNr)
);

-- Abhängig von Saal: zusammengesetzter FK
create table Vorstellung (
  KinoNr           integer   not null
, SaalNr           integer   not null
, Beginnzeitpunkt  datetime  not null
, primary key (KinoNr, SaalNr, Beginnzeitpunkt)
, foreign key (KinoNr, SaalNr) references Saal(KinoNr, SaalNr)
);

queries.sql:
select lnr, lname
     , (select count(*)
          from lt
         where lt.lnr = l.lnr   -- korreliert
       ) "#lieferungen"
  from l;

(select lnr from lt where tnr = 'T1')
intersect
(select lnr from lt where tnr = 'T2');

(select lnr from lt where tnr = 'T1')
except
(select lnr from lt where tnr = 'T2');
